// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

contract LogicV1 {
    // PENTING: variabel pertama harus sama persis dengan Proxy
    address public implementation;
    address public owner;
    
    // State variable yang akan kita pakai
    uint256 public value;

    function setValue(uint256 _value) public {
        value = _value;
    }

    function getValue() public view returns (uint256) {
        return value;
    }

    function version() public pure returns (string memory) {
        return "V1";
    }
}

contracts/LogicV2.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

contract LogicV2 {
    // HARUS sama persis dengan LogicV1 dan Proxy — jangan diubah urutannya!
    address public implementation;
    address public owner;
    uint256 public value;

    // Fitur lama tetap ada
    function setValue(uint256 _value) public {
        value = _value;
    }

    function getValue() public view returns (uint256) {
        return value;
    }

    // Fitur BARU di V2
    function multiplyValue(uint256 multiplier) public {
        value = value * multiplier;
    }

    function version() public pure returns (string memory) {
        return "V2";
    }
}

